# VaultLegacy - Wire All 6 Main Screens
# Place this file inside C:\Users\HP\Desktop\VaultLegacy\
# Then run: .\wire_all_screens.ps1

$root = Split-Path -Parent $MyInvocation.MyCommand.Path
$FE = Join-Path $root "frontend"

Write-Host ""
Write-Host "VaultLegacy - Wiring 6 main screens to real backend API" -ForegroundColor Cyan
Write-Host ""

if (-not (Test-Path $FE)) {
    Write-Host "ERROR: Cannot find frontend folder at: $FE" -ForegroundColor Red
    Write-Host "Make sure this script is inside your VaultLegacy folder." -ForegroundColor Red
    Read-Host "Press Enter to exit"
    exit 1
}

Write-Host "[1/6] OwnerDashboardScreen.tsx..." -ForegroundColor Yellow
$s = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllText("$FE\src\screens\OwnerDashboardScreen.tsx", $s, [System.Text.UTF8Encoding]::new($false))
Write-Host "      Done" -ForegroundColor Green

Write-Host "[2/6] ExecutorDashboardScreen.tsx..." -ForegroundColor Yellow
$s = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllText("$FE\src\screens\ExecutorDashboardScreen.tsx", $s, [System.Text.UTF8Encoding]::new($false))
Write-Host "      Done" -ForegroundColor Green

Write-Host "[3/6] BeneficiaryDashboardScreen.tsx..." -ForegroundColor Yellow
$s = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllText("$FE\src\screens\BeneficiaryDashboardScreen.tsx", $s, [System.Text.UTF8Encoding]::new($false))
Write-Host "      Done" -ForegroundColor Green

Write-Host "[4/6] DepositHistoryScreen.tsx..." -ForegroundColor Yellow
$s = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllText("$FE\src\screens\DepositHistoryScreen.tsx", $s, [System.Text.UTF8Encoding]::new($false))
Write-Host "      Done" -ForegroundColor Green

Write-Host "[5/6] DeathConfirmationScreen.tsx..." -ForegroundColor Yellow
$s = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllText("$FE\src\screens\DeathConfirmationScreen.tsx", $s, [System.Text.UTF8Encoding]::new($false))
Write-Host "      Done" -ForegroundColor Green

Write-Host "[6/6] CreateVaultScreen.tsx..." -ForegroundColor Yellow
$s = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllText("$FE\src\screens\CreateVaultScreen.tsx", $s, [System.Text.UTF8Encoding]::new($false))
Write-Host "      Done" -ForegroundColor Green

Write-Host ""
Write-Host "============================================" -ForegroundColor Green
Write-Host " 6 screens wired to real backend API." -ForegroundColor Green
Write-Host "============================================" -ForegroundColor Green
Write-Host ""
Write-Host "Screens wired:" -ForegroundColor White
Write-Host "  OwnerDashboard       real vaults, check-in, deposit recording" -ForegroundColor Gray
Write-Host "  ExecutorDashboard    real transfers, ack deposits, confirm death" -ForegroundColor Gray
Write-Host "  BeneficiaryDashboard real vault data, share percentage, BTC on execution" -ForegroundColor Gray
Write-Host "  DepositHistory       real deposits, executor acknowledgment" -ForegroundColor Gray
Write-Host "  DeathConfirmation    real cert hash, real 72h window, real fraud flag" -ForegroundColor Gray
Write-Host "  CreateVault          real vault creation saved to database" -ForegroundColor Gray
Write-Host ""
Write-Host "Now run wire_final.ps1 if you have not already (wires last 3 screens)." -ForegroundColor Yellow
Write-Host ""
Read-Host "Press Enter to close"
